// Microservice decomposition:

// Service 1: user-service (port 8081)
// Responsibilities: login, registration, profile, KYC verification
// Database: users_db (users, KYC docs)
// Calls: none (other services call it)

// Service 2: market-service (port 8082)
// Responsibilities: real-time stock prices, historical data, market status
// Database: market_db (price history, instruments)
// Calls: none (data source for other services)

// Service 3: order-service (port 8083)
// Responsibilities: buy/sell orders, order book, order lifecycle
// Database: orders_db (orders, trades)
// Calls:
//   - user-service (sync): validate user account
//   - market-service (sync): get current price for order validation
//   - payment-service (sync): debit funds for buy orders
//   - alert-service (async): notify on order execution

// Service 4: payment-service (port 8084)
// Responsibilities: fund transfers, withdrawals, balance
// Database: payments_db (transactions, balances)
// Calls:
//   - user-service (sync): validate user identity
//   - async: publishes 'payment.completed' events

public class DecompositionExample {
    public static void main(String[] args) {
        System.out.println("4 services: user, market, order, payment");
        System.out.println("Each owns its own database");
        System.out.println("Order->Market: sync (need price to validate)");
        System.out.println("Order->Alert: async (notification can be eventual)");
    }
}

