import org.springframework.http.*;
import org.springframework.web.client.*;
import org.springframework.stereotype.Service;

@Service
public class ReservationService {
    private final RestTemplate rt;
    private static final String SEAT_URL = "http://seat-service";
    ReservationService(RestTemplate rt) { this.rt = rt; }

    public boolean checkSeatAvailable(String concertId, String seatId) {
        try {
            SeatDto seat = rt.getForObject(
                SEAT_URL + "/api/concerts/" + concertId + "/seats/" + seatId,
                SeatDto.class);
            return seat != null && seat.available();
        } catch (HttpClientErrorException.NotFound e) {
            return false;  // seat/concert not found = not available
        } catch (RestClientException e) {
            throw new RuntimeException("Seat service unavailable", e);
        }
    }

    public ReservationDto reserveSeat(String concertId, String seatId, String userId) {
        try {
            return rt.postForObject(
                SEAT_URL + "/api/reservations",
                new ReservationRequest(concertId, seatId, userId),
                ReservationDto.class);
        } catch (HttpClientErrorException.Conflict e) {
            throw new RuntimeException("Seat " + seatId + " already reserved");
        } catch (HttpClientErrorException.NotFound e) {
            throw new RuntimeException("Concert or seat not found");
        }
    }

    public void cancelReservation(String reservationId) {
        try {
            rt.delete(SEAT_URL + "/api/reservations/" + reservationId);
        } catch (HttpClientErrorException.NotFound e) {
            throw new RuntimeException("Reservation " + reservationId + " not found");
        }
    }
}

