import org.springframework.http.*;
import org.springframework.web.client.*;
import org.springframework.stereotype.Service;
import java.util.UUID;

@Service
public class PaymentService {
    private final RestTemplate restTemplate;
    private static final String GATEWAY_URL = "http://payment-gateway-service";
    private static final String API_KEY = "rzp_test_abc123";  // from @Value in real code

    PaymentService(RestTemplate rt) { restTemplate = rt; }

    public PaymentResult processPayment(String orderId, double amount, String currency) {
        // Build request with custom headers:
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        headers.set("X-API-Key", API_KEY);
        headers.set("X-Idempotency-Key", UUID.randomUUID().toString());

        HttpEntity<PaymentRequest> request = new HttpEntity<>(
            new PaymentRequest(orderId, amount, currency), headers);

        try {
            ResponseEntity<PaymentResult> response = restTemplate.exchange(
                GATEWAY_URL + "/api/payments",
                HttpMethod.POST,
                request,
                PaymentResult.class);
            return response.getBody();

        } catch (HttpClientErrorException e) {
            if (e.getStatusCode() == HttpStatus.PAYMENT_REQUIRED) {
                return new PaymentResult(null, "DECLINED", "Payment declined by gateway");
            }
            if (e.getStatusCode() == HttpStatus.TOO_MANY_REQUESTS) {
                throw new RuntimeException("Rate limited by payment gateway");
            }
            throw new RuntimeException("Payment gateway error: " + e.getMessage());
        }
    }
}

