import org.springframework.http.*;
import org.springframework.http.client.*;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.client.RestTemplate;
import org.springframework.context.annotation.*;
import org.springframework.stereotype.Component;
import java.io.IOException;
import java.util.List;

@Component
public class TokenPropagationInterceptor implements ClientHttpRequestInterceptor {

    @Override
    public ClientHttpResponse intercept(
            HttpRequest request,
            byte[] body,
            ClientHttpRequestExecution execution) throws IOException {

        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.getCredentials() instanceof String token) {
            // Add JWT to the outgoing inter-service request:
            request.getHeaders().set(HttpHeaders.AUTHORIZATION, "Bearer " + token);
        }
        return execution.execute(request, body);
    }
}

@Configuration
class RestTemplateConfig {
    @Bean
    public RestTemplate restTemplate(TokenPropagationInterceptor interceptor) {
        RestTemplate rt = new RestTemplate();
        rt.setInterceptors(List.of(interceptor));
        return rt;
    }
}

