@Service
class OrderOrchestrationService {
    private final RestTemplate rt;
    private static final String USER = "http://user-service";
    private static final String REST = "http://restaurant-service";
    private static final String PAY  = "http://payment-service";
    OrderOrchestrationService(RestTemplate rt) { this.rt = rt; }

    public String placeOrder(String userId, String restaurantId, List<OrderItem> items) {
        // 1. Check user:
        UserStatus user = rt.getForObject(USER+"/api/users/"+userId+"/status", UserStatus.class);
        if (user == null || !user.active()) throw new IllegalStateException("User not active");
        // 2. Check restaurant:
        RestaurantStatus restaurant = rt.getForObject(REST+"/api/restaurants/"+restaurantId+"/available", RestaurantStatus.class);
        if (restaurant == null || !restaurant.open()) throw new IllegalStateException("Restaurant closed");
        // 3. Calculate total:
        double total = items.stream().mapToDouble(OrderItem::total).sum();
        // 4. Process payment:
        String orderId = "ORD-"+java.util.UUID.randomUUID().toString().substring(0,8);
        PaymentResult2 payment = rt.postForObject(PAY+"/api/payments",
            new PaymentRequest2(orderId, total), PaymentResult2.class);
        if (payment == null || !payment.success()) throw new IllegalStateException("Payment failed");
        // 5. Save order (simplified):
        System.out.println("Order "+orderId+" placed at "+restaurant.name()+" for ₹"+total);
        // 6. Async events:
        System.out.println("[EVENT] order.placed published for order "+orderId);
        return orderId;
    }
}

